```javascript
// debounce example
// ---------------
//
// This script demonstrates the use of a debounce function, which ensures that a given
// function is executed at most once within a specified time interval.

// debounce function
// ----------------
//
// Calls the function `func` only if at most `wait` milliseconds have passed since the
// last call.
function debounce(func, wait) {
  let lastCallback;

  return () => {
    const now = Date.now();

    if (lastCallback && now - lastCallback < wait) {
      // Clear and reset the last callback
      window.clearTimeout(lastCallback);
    }

    lastCallback = window.setTimeout(() => {
      // Execute the function
      func();
      // Clear the last callback
      lastCallback = undefined;
    }, wait);
  };
}

// usage example
// ------------
//
// Example use case: throttling the `blur` event on an input element.

document.addEventListener('DOMContentLoaded', () => {
  const input = document.querySelector('input');

  input.onblur = debounce(() => {
    console.log('Input lost focus');
  }, 500);
});
```
Explanation:
The `debounce` function accepts a function `func` and an interval in milliseconds `wait`. It returns a new function that keeps track of the last time `func` was called using `lastCallback`. If the `wait` milliseconds have passed since the last call, `func` is called and `lastCallback` is set to the current time. If the `wait` time hasn't passed, the previous debounced call is canceled and the new one is rescheduled for `wait` milliseconds in the future. This ensures that `func` is called at most once per `wait` milliseconds, even if the input events fire more often.
